import React from 'react'
import '../styles.css'

const MealsContainer = ({meals}) => {
    // console.log(meals[0].title);
    return (
        <>
    <div>{meals.map(e => {
        {console.log(e.id)}
        <div key={e.id}>{e.title}</div>
        })}
    </div>
    </>
    );
};

export default MealsContainer
